const StartChildWorkflowExecutionFailedCause = @import("start_child_workflow_execution_failed_cause.zig").StartChildWorkflowExecutionFailedCause;
const WorkflowType = @import("workflow_type.zig").WorkflowType;

/// Provides the details of the `StartChildWorkflowExecutionFailed` event.
pub const StartChildWorkflowExecutionFailedEventAttributes = struct {
    /// The cause of the failure. This information is generated by the system and
    /// can be useful for diagnostic purposes.
    ///
    /// When `cause` is set to `OPERATION_NOT_PERMITTED`, the decision fails because
    /// it lacks sufficient permissions.
    /// For details and example IAM policies, see [
    /// Using IAM to Manage Access to Amazon SWF
    /// Workflows](https://docs.aws.amazon.com/amazonswf/latest/developerguide/swf-dev-iam.html) in the *Amazon SWF Developer Guide*.
    cause: StartChildWorkflowExecutionFailedCause,

    /// The data attached to the event that the decider can use in subsequent
    /// workflow tasks.
    /// This data isn't sent to the child workflow execution.
    control: ?[]const u8,

    /// The ID of the `DecisionTaskCompleted` event corresponding to the decision
    /// task that resulted in the `StartChildWorkflowExecution`
    /// Decision to request this child workflow execution. This information can be
    /// useful for diagnosing problems by tracing back the chain of events.
    decision_task_completed_event_id: i64 = 0,

    /// When the `cause` is `WORKFLOW_ALREADY_RUNNING`, `initiatedEventId` is the ID
    /// of the `StartChildWorkflowExecutionInitiated`
    /// event that corresponds to the `StartChildWorkflowExecution`
    /// Decision to start the workflow execution. You can use this information to
    /// diagnose
    /// problems by tracing back the chain of events leading up to this event.
    ///
    /// When the `cause` isn't `WORKFLOW_ALREADY_RUNNING`, `initiatedEventId` is set
    /// to `0` because the
    /// `StartChildWorkflowExecutionInitiated` event doesn't exist.
    initiated_event_id: i64 = 0,

    /// The `workflowId` of the child workflow execution.
    workflow_id: []const u8,

    /// The workflow type provided in the `StartChildWorkflowExecution`
    /// Decision that failed.
    workflow_type: WorkflowType,

    pub const json_field_names = .{
        .cause = "cause",
        .control = "control",
        .decision_task_completed_event_id = "decisionTaskCompletedEventId",
        .initiated_event_id = "initiatedEventId",
        .workflow_id = "workflowId",
        .workflow_type = "workflowType",
    };
};
